144: // shouldShowRows determines if row panels will be created (showRows logic)
145: func shouldShowRows(rows []interface{}) bool {
146: 	for _, rowInterface := range rows {
147: 		row, ok := rowInterface.(map[string]interface{})
148: 		if !ok {
149: 			continue
150: 		}
151: 
152: 		collapse := schemaversion.GetBoolValue(row, "collapse")
153: 		showTitle := schemaversion.GetBoolValue(row, "showTitle")
154: 		repeat := schemaversion.GetStringValue(row, "repeat")
155: 
156: 		if collapse || showTitle || repeat != "" {
157: 			return true
158: 		}
159: 	}
160: 	return false
161: }
162: 
163: // applyRowPanelDefaults applies panel defaults to panels within a row based on frontend logic
164: func applyRowPanelDefaults(row map[string]interface{}, showRows bool) {
165: 	rowPanels, ok := row["panels"].([]interface{})
166: 	if !ok {
167: 		return
168: 	}
169: 
170: 	collapse := schemaversion.GetBoolValue(row, "collapse")
171: 
172: 	// Frontend: if (rowPanelModel && rowPanel.collapsed) { push(panel) } else { push(new PanelModel(panel)) }
173: 	// Only non-collapsed panels get PanelModel defaults (refId: "A", overrides: [], etc.)
174: 	applyDefaults := !showRows || !collapse
175: 
176: 	if !applyDefaults {
177: 		return
178: 	}
179: 
180: 	for _, panelInterface := range rowPanels {
181: 		panel, ok := panelInterface.(map[string]interface{})
182: 		if !ok {
183: 			continue
184: 		}
185: 		applyPanelDefaults(panel)
186: 	}
187: }
